backgrounds:
LaTeX commands: \newcommand{\pa}{\partial}
\newcommand{\vdm}{\boldsymbol{\Delta}}
Definition (Calogero Model): The Calogero model is defined by the following Hamiltonian.
\begin{equation}
H = -\frac{1}{2}\sum_{i=1}^N\pa_i^2+\sum_{j<i}\frac{\lambda(\lambda-1)}{(x_i-x_j)^2}
\end{equation}
$N\in \mathbb{Z}$ and $\lambda\in \mathbb{R}$.
Definition (Dilatation Generator): $D$ is defined as follows.
\begin{equation}
D = -\frac{i}{4}\sum_{i=1}^N\left(x_i\pa_i+\pa_ix_i\right).
\end{equation}
Definition (Special Conformal Transformation): $K$ is defined as follows.
\begin{equation}
K = \frac{1}{2}\sum_{i=1}^Nx_i^2.
\end{equation}
Definition (Quadratic Casimir Operator): $C_2$ is defined as follows.
\begin{equation}
C_2\equiv \frac{1}{2}\left(H\,K+K\,H\right)-D^2.
\end{equation}
Definition ($l_0$ Operator): $l_0$ is defined as follows.
\begin{equation}
l_0 = \frac{1}{2}(H + K).
\end{equation}
Definition (Change of Coordinates): We define a new coordinate system $(X,y_1,\cdots,y_{N-1})$ as follows.
\begin{equation}
X\equiv \frac{1}{{N}}\sum_{i=1}^Nx_i.
\end{equation}
and
\begin{equation}
y_k = \sqrt{\frac{k}{k+1}}\left(\,x_{k+1}-\frac{1}{k}\sum_{j=1}^k x_j\right),\qquad 1\leq k\leq N-1.
\end{equation}
We define
\begin{equation}
y_N = \sqrt{N} X.
\end{equation}
We denote
\begin{equation}
\mathbf{y} = (y_1,\cdots, y_{N-1}).
\end{equation}
Definition (Matrix for the Change of Coordinates): The $N$-by-$N$ matrix $A$ is defined by
\begin{eqnarray}
x_i=\sum_{k=1}^NA_{ik}y_{k}.
\end{eqnarray}
Definition (Double-Index): We denote by $[i,j]$ (where $i$ and $j$ are integers and $1\le j < i \le N$) the double-index which runs over all the $N(N-1)/2$ independent choices of pairs.
We will use the letters $a$ and $c$ to denote a double-index.
Definition ($b^{[i,j]}$): For each double-index $[i,j]$, define
\begin{equation}
b^{[i,j]}_k = \frac{1}{\sqrt{2}}\left(A_{ik}-A_{jk}\right).
\end{equation}
Definition ($\mathbf{b}^a$): For each double-index $a$,
\begin{equation}
\mathbf{b}^a=(b^a_1,\cdots, b^a_{N-1})\in \mathbb{R}^{N-1}.
\end{equation}
Definition (Center-of-Mass and Relative Operators): We define $H_X$ and $H_{\rm rel}$ by the following decomposition
\begin{equation}
H=H_X + H_{\rm rel},
\end{equation}
where $H_X$ only involves the coordinate $X$ and $H_{\rm rel}$ only involves $\mathbf{y}$.
Definition (Polar Coordinates): Define $r$ (where $r\ge 0$) by
\begin{equation}
r^2 = \mathbf{y} \cdot \mathbf{y}.
\end{equation}
Denote by $S^{N-2}$ the unit sphere in the space of $\mathbf{y}$.
Denote by $\nabla^2_{S^{N-2}}$ is the Laplacian on $S^{N-2}$.
Definition ($\Theta^a$): For each double-index $a$, define $\Theta^a$ by
\begin{equation}
r\,\cos\Theta^a = \mathbf{b}^a\cdot \mathbf{y}=\sum_{i=1}^{N-1}b^a_iy_i.
\end{equation}
Definition (Angular Operator): The angular operator is defined as follows.
\begin{equation}
\hat{L}^2_{S^{N-2}} = -\nabla^2_{S^{N-2}}+\sum_{a}\frac{\lambda(\lambda-1)}{(\cos\Theta^a)^2}.
\end{equation}
Definition ($\vdm(\mathbf{y})$): $\vdm(\mathbf{y})$ is defined as follows.
\begin{equation}
\vdm(\mathbf{y}) =\prod_{j<i}\left(\frac{\mathbf{b}^{[i,j]}\cdot \mathbf{y}}{r}\right)= \prod_a\,\cos\Theta^a
\end{equation}
Definition (Similarity Transformation): We will denote by a caligraphic script, any operator related to our original algebra by the following similarity transformation, e.g.,
\begin{equation}\label{eq:similarity}
\mathcal{H}= \vdm^{-\lambda} H\vdm^\lambda, \qquad \mathcal{D}= \vdm^{-\lambda} D\vdm^\lambda,\qquad \mathcal{K}= \vdm^{-\lambda} K\vdm^\lambda,\qquad \hat{\mathcal{L}}^2_{S^{N-2}}=\vdm^{-\lambda} \hat{L}^2_{S^{N-2}} \vdm^\lambda.
\end{equation}
Definition (Center-of-Mass and Relative Operators after Similarity Transformation): We define $\mathcal{H}_X$ and $\mathcal{H}_{\rm rel}$ by the following decomposition
\begin{equation}
\mathcal{H}=\mathcal{H}_X + \mathcal{H}_{\rm rel},
\end{equation}
where $\mathcal{H}_X$ only involves the coordinate $X$ and $\mathcal{H}_{\rm rel}$ only involves $\mathbf{y}$.
Similarly,
\begin{equation}
\mathcal{H}= \mathcal{H}_X+\mathcal{H}_{\rm rel}, \qquad \mathcal{K} = \mathcal{K}_X+\mathcal{K}_{\rm rel},\qquad \mathcal{D} = \mathcal{D}_X+\mathcal{D}_{\rm rel}.
\end{equation}
Similarly,
\begin{equation}
\mathcal{C}_2 = \mathcal{C}_2^X + \mathcal{C}_2^{\rm rel}.
\end{equation}
Definition ($\ell_0^{\rm rel}$): $\ell_0^{\rm rel}$ is defined by
\begin{eqnarray}
\ell_0^{\rm rel} = \frac{1}{2}(\mathcal{H}_{\rm rel} + \mathcal{K}_{\rm rel}).
\end{eqnarray}
Definition (Analytic Continuation of Variables): We formally define $\kappa = r^2/2$, where $\kappa\in (-\infty,\infty)$.
Definition (Polar Coordinates for $N=3$): In the $N=3$ case, we define $(r,\vartheta)$ by
\begin{equation}
\mathbf{y} = (r \cos\vartheta, r \sin\vartheta).
\end{equation}
Definition (Conformal Dimension for the Principal Series for $N=3$): In the $N=3$ case, we define
\begin{equation}
\Delta_\sigma = \frac{1}{2}(1+3i\sigma),\qquad \sigma\in\mathbb{R}.
\end{equation}
Definition (Analytic Continuation of Variables for $N=3$): In the $N=3$ case, we define
\begin{equation}
\vartheta = i\chi - \frac{\pi}{2}.
\end{equation}
Definition ($\Psi_{n,\sigma}(\kappa,\chi)$): In the $N=3$ case, for each $n\in \mathbb{Z}$ and $\sigma \in \mathbb{R}$, denote by $\Psi_{n,\sigma}(\kappa,\chi)$ the solution to the following equations.
\begin{equation}
\ell_0^{\rm rel}\Psi_{n\sigma}(\kappa,\chi)=-n\Psi_{n\sigma}(\kappa,\chi)~, \qquad \mathcal{C}_2^{\rm rel}\Psi_{n\sigma}(\kappa,\chi) = \Delta_\sigma(\Delta_\sigma-1)\Psi_{n\sigma}(\kappa,\chi).
\end{equation}
Defintion (Separation of Variables for $N=3$): In the $N=3$ case, $\Psi_{n\sigma}$ admits separation of variables.
Define $\psi_n$ and $Y_\sigma$ (up to some constant factor in $\sigma$, $\lambda$, and $n$) by
\begin{equation}
\Psi_{n\sigma}(\kappa,\chi)=\psi_n^\sigma(\kappa)Y_\sigma(\chi).
\end{equation}
Definition (Gegenbauer Function): For $\gamma\in\mathbb{R}$ and $\nu\in\mathbb{C}$, denote by $C^\gamma_\nu$ the Gegenbauer Function.

